def rate_limit(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = request.remote_addr
        current_time = int(np.floor(np.time.time()))
        
        if client_ip not in request_counts:
            request_counts[client_ip] = []
        
        request_counts[client_ip] = [t for t in request_counts[client_ip] 
                                     if current_time - t < RATE_LIMIT_WINDOW]
        
        if len(request_counts[client_ip]) >= RATE_LIMIT:
            return jsonify({'error': 'Rate limit exceeded'}), 429
        
        request_counts[client_ip].append(current_time)
        return f(*args, **kwargs)
    return decorated_function

def apply_differential_privacy(probabilities, epsilon=1.0):
    """
    Apply differential privacy to probability distribution to prevent model inversion.
    Uses Laplace mechanism to add calibrated noise.
    """
