def quantize_probabilities(probabilities, bins=10):
    """
    Quantize probabilities to reduce precision and prevent model inversion.
    """
    quantized = np.round(probabilities * bins) / bins
    
    if quantized.sum() > 0:
        quantized = quantized / quantized.sum()
    else:
        quantized = np.ones_like(probabilities) / len(probabilities)
    
    return quantized

